import React, { useState } from 'react';
import { menuCategories } from './menuData';
import './Menu.css';

const Menu = () => {
  const [activeCategory, setActiveCategory] = useState(1);
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);

  const handleAddToCart = (item) => {
    setCart([...cart, { ...item, cartId: Date.now() }]);
  };

  const handleRemoveFromCart = (cartId) => {
    setCart(cart.filter(item => item.cartId !== cartId));
  };

  const getCartTotal = () => {
    return cart.reduce((total, item) => total + item.price, 0);
  };

  const activeCategoryData = menuCategories.find(cat => cat.id === activeCategory);

  return (
    <div className="menu-page">
      {/* Menu Header */}
      <section className="menu-hero">
        <div className="menu-hero-content">
          <h1>Our Menu</h1>
          <p>Explore our delicious range of dishes</p>
        </div>
      </section>

      <div className="menu-container">
        {/* Category Sidebar */}
        <aside className="category-sidebar">
          <h3>Categories</h3>
          <ul className="category-list">
            {menuCategories.map(category => (
              <li 
                key={category.id}
                className={`category-item ${activeCategory === category.id ? 'active' : ''}`}
                onClick={() => setActiveCategory(category.id)}
              >
                <i className={`fas ${category.icon}`}></i>
                <span>{category.name}</span>
                <span className="item-count">{category.items.length}</span>
              </li>
            ))}
          </ul>
        </aside>

        {/* Menu Items */}
        <main className="menu-content">
          <div className="category-header">
            <h2>
              <i className={`fas ${activeCategoryData?.icon}`}></i>
              {activeCategoryData?.name}
            </h2>
            <span className="item-total">{activeCategoryData?.items.length} items</span>
          </div>

          <div className="menu-items-grid">
            {activeCategoryData?.items.map(item => (
              <div key={item.id} className="menu-item-card" onClick={() => setSelectedItem(item)}>
                <div className="menu-item-image">
                  <img 
                    src={item.image || 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=300&h=200&fit=crop'} 
                    alt={item.name}
                    onError={(e) => {
                      e.target.src = 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=300&h=200&fit=crop';
                    }}
                  />
                  {item.discount && (
                    <div className="discount-badge">{item.discount}% OFF</div>
                  )}
                </div>
                <div className="menu-item-info">
                  <h4>{item.name}</h4>
                  <p>{item.description}</p>
                </div>
                <div className="menu-item-action">
                  <div className="price-info">
                    <span className="original-price">₹{item.price}</span>
                  </div>
                  <button 
                    className="add-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleAddToCart(item);
                    }}
                  >
                    Add +
                  </button>
                </div>
              </div>
            ))}
          </div>
        </main>

        {/* Cart Sidebar */}
        <aside className={`cart-sidebar ${showCart ? 'open' : ''}`}>
          <div className="cart-header">
            <h3>Your Cart</h3>
            <button className="close-cart" onClick={() => setShowCart(false)}>
              <i className="fas fa-times"></i>
            </button>
          </div>
          
          <div className="cart-items">
            {cart.length === 0 ? (
              <div className="empty-cart">
                <i className="fas fa-shopping-cart"></i>
                <p>Your cart is empty</p>
              </div>
            ) : (
              cart.map(item => (
                <div key={item.cartId} className="cart-item">
                  <div className="cart-item-info">
                    <h5>{item.name}</h5>
                    <span className="cart-item-price">₹{item.price}</span>
                  </div>
                  <button 
                    className="remove-btn"
                    onClick={() => handleRemoveFromCart(item.cartId)}
                  >
                    <i className="fas fa-trash"></i>
                  </button>
                </div>
              ))
            )}
          </div>

          {cart.length > 0 && (
            <div className="cart-footer">
              <div className="cart-total">
                <span>Total</span>
                <span className="total-amount">₹{getCartTotal()}</span>
              </div>
              <button className="checkout-btn">Checkout</button>
            </div>
          )}
        </aside>
      </div>

      {/* Floating Cart Button */}
      {cart.length > 0 && !showCart && (
        <button className="floating-cart" onClick={() => setShowCart(true)}>
          <i className="fas fa-shopping-cart"></i>
          <span className="cart-count">{cart.length}</span>
        </button>
      )}

      {/* Recipe Detail Modal */}
      {selectedItem && (
        <div className="modal-overlay" onClick={() => setSelectedItem(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setSelectedItem(null)}>
              <i className="fas fa-times"></i>
            </button>
            
            <div className="modal-image">
              <img 
                src={selectedItem.image || 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=300&h=200&fit=crop'} 
                alt={selectedItem.name}
                onError={(e) => {
                  e.target.src = 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=300&h=200&fit=crop';
                }}
              />
            </div>
            
            <div className="modal-body">
              <h2>{selectedItem.name}</h2>
              <p className="modal-description">{selectedItem.description}</p>
              
              <div className="modal-price">
                <span className="original-price">₹{selectedItem.price}</span>
                {selectedItem.discount && (
                  <span className="discount-text">{selectedItem.discount}% OFF</span>
                )}
              </div>

              {/* Show full recipe details if available */}
              {selectedItem.ingredients && (
                <div className="recipe-section">
                  <h3>Ingredients</h3>
                  <ul className="ingredients-list">
                    {selectedItem.ingredients.map((ingredient, index) => (
                      <li key={index}>{ingredient}</li>
                    ))}
                  </ul>
                </div>
              )}

              {selectedItem.preparationSteps && (
                <div className="recipe-section">
                  <h3>Preparation Steps</h3>
                  <ol className="steps-list">
                    {selectedItem.preparationSteps.map((step, index) => (
                      <li key={index}>{step}</li>
                    ))}
                  </ol>
                </div>
              )}

              {selectedItem.nutritionalInfo && (
                <div className="recipe-section">
                  <h3>Nutritional Information</h3>
                  <div className="nutritional-grid">
                    {Object.entries(selectedItem.nutritionalInfo).map(([key, value]) => (
                      <div key={key} className="nutritional-item">
                        <span className="nutrient-name">{key.replace(/([A-Z])/g, ' $1').trim()}</span>
                        <span className="nutrient-value">{value}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {selectedItem.optionalAdditions && (
                <div className="recipe-section">
                  <h3>Optional Additions</h3>
                  <ul className="optional-list">
                    {selectedItem.optionalAdditions.map((addition, index) => (
                      <li key={index}>{addition}</li>
                    ))}
                  </ul>
                </div>
              )}

              <button 
                className="add-btn modal-add-btn"
                onClick={() => {
                  handleAddToCart(selectedItem);
                  setSelectedItem(null);
                }}
              >
                Add to Cart
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Menu;
